/**
 * Unit tests for effort-detector.ts
 *
 * Covers:
 * - DEFAULT_EFFORT_LEVEL constant value (CC 2.1.94 alignment)
 * - detectEffortLevel() detection order: input > env > default
 * - effortTokenBudget() multipliers per level
 * - Invalid/missing effort values fall through to default
 * - CLAUDE_EFFORT env var override
 */

import { describe, test, expect, beforeEach, afterEach } from 'vitest';
import {
  DEFAULT_EFFORT_LEVEL,
  detectEffortLevel,
  effortTokenBudget,
} from '../../lib/effort-detector.js';
import type { HookInput } from '../../types.js';

function makeInput(overrides: Record<string, unknown> = {}): HookInput {
  return {
    tool_name: 'Bash',
    session_id: 'test-session',
    tool_input: {},
    ...overrides,
  } as HookInput;
}

describe('lib/effort-detector', () => {
  const savedEnv = process.env.CLAUDE_EFFORT;

  afterEach(() => {
    // Restore env after each test
    if (savedEnv === undefined) {
      delete process.env.CLAUDE_EFFORT;
    } else {
      process.env.CLAUDE_EFFORT = savedEnv;
    }
  });

  describe('DEFAULT_EFFORT_LEVEL', () => {
    test('is "high" (aligned with CC 2.1.94 default)', () => {
      expect(DEFAULT_EFFORT_LEVEL).toBe('high');
    });

    test('is a valid EffortLevel value', () => {
      expect(['low', 'medium', 'high']).toContain(DEFAULT_EFFORT_LEVEL);
    });
  });

  describe('detectEffortLevel', () => {
    beforeEach(() => {
      delete process.env.CLAUDE_EFFORT;
    });

    test('returns effort_level from input when present and valid', () => {
      const input = makeInput({ effort_level: 'low' });
      expect(detectEffortLevel(input)).toBe('low');
    });

    test('accepts "medium" from input', () => {
      const input = makeInput({ effort_level: 'medium' });
      expect(detectEffortLevel(input)).toBe('medium');
    });

    test('accepts "high" from input', () => {
      const input = makeInput({ effort_level: 'high' });
      expect(detectEffortLevel(input)).toBe('high');
    });

    test('ignores invalid effort_level values in input', () => {
      const input = makeInput({ effort_level: 'turbo' });
      expect(detectEffortLevel(input)).toBe(DEFAULT_EFFORT_LEVEL);
    });

    test('ignores non-string effort_level values', () => {
      const input = makeInput({ effort_level: 42 });
      expect(detectEffortLevel(input)).toBe(DEFAULT_EFFORT_LEVEL);
    });

    test('ignores null effort_level', () => {
      const input = makeInput({ effort_level: null });
      expect(detectEffortLevel(input)).toBe(DEFAULT_EFFORT_LEVEL);
    });

    test('falls back to CLAUDE_EFFORT env var when input has no effort_level', () => {
      process.env.CLAUDE_EFFORT = 'low';
      const input = makeInput();
      expect(detectEffortLevel(input)).toBe('low');
    });

    test('CLAUDE_EFFORT env var accepts "medium"', () => {
      process.env.CLAUDE_EFFORT = 'medium';
      expect(detectEffortLevel(makeInput())).toBe('medium');
    });

    test('ignores invalid CLAUDE_EFFORT env var', () => {
      process.env.CLAUDE_EFFORT = 'ultra';
      expect(detectEffortLevel(makeInput())).toBe(DEFAULT_EFFORT_LEVEL);
    });

    test('input effort_level takes precedence over CLAUDE_EFFORT env', () => {
      process.env.CLAUDE_EFFORT = 'low';
      const input = makeInput({ effort_level: 'medium' });
      expect(detectEffortLevel(input)).toBe('medium');
    });

    test('returns DEFAULT_EFFORT_LEVEL ("high") when no effort_level and no env var', () => {
      delete process.env.CLAUDE_EFFORT;
      const input = makeInput();
      expect(detectEffortLevel(input)).toBe('high');
    });
  });

  describe('effortTokenBudget', () => {
    test('low effort = 25% of base budget', () => {
      expect(effortTokenBudget('low', 800)).toBe(200);
      expect(effortTokenBudget('low', 1000)).toBe(250);
    });

    test('medium effort = 100% of base budget (no multiplier)', () => {
      expect(effortTokenBudget('medium', 800)).toBe(800);
      expect(effortTokenBudget('medium', 1000)).toBe(1000);
    });

    test('high effort = 150% of base budget', () => {
      expect(effortTokenBudget('high', 800)).toBe(1200);
      expect(effortTokenBudget('high', 1000)).toBe(1500);
    });

    test('rounds to nearest integer', () => {
      expect(effortTokenBudget('low', 100)).toBe(25);
      expect(effortTokenBudget('low', 99)).toBe(25); // Math.round(24.75)
      expect(effortTokenBudget('high', 99)).toBe(149); // Math.round(148.5)
    });

    test('handles zero base budget', () => {
      expect(effortTokenBudget('low', 0)).toBe(0);
      expect(effortTokenBudget('medium', 0)).toBe(0);
      expect(effortTokenBudget('high', 0)).toBe(0);
    });
  });
});
